const { redis } = require('../config/redis');

class CacheService {
  // 缓存键前缀
  static PREFIXES = {
    PIXEL: 'pixel:',
    PIXEL_GRID: 'pixel_grid:',
    USER_STATE: 'user_state:',
    LEADERBOARD: 'leaderboard:',
    CHAT_MESSAGE: 'chat:',
    ALLIANCE: 'alliance:',
    USER_PROFILE: 'user_profile:',
    REGION_STATS: 'region_stats:'
  };

  // 缓存过期时间（秒）
  static TTL = {
    PIXEL: 3600, // 1小时
    PIXEL_GRID: 1800, // 30分钟
    USER_STATE: 300, // 5分钟
    LEADERBOARD: 600, // 10分钟
    CHAT_MESSAGE: 86400, // 24小时
    ALLIANCE: 1800, // 30分钟
    USER_PROFILE: 3600, // 1小时
    REGION_STATS: 1800 // 30分钟
  };

  /**
   * 设置缓存
   */
  static async set(key, value, ttl = 3600) {
    try {
      const serializedValue = JSON.stringify(value);
      await redis.setex(key, ttl, serializedValue);
      console.log(`缓存设置成功: ${key}`);
    } catch (error) {
      console.error('缓存设置失败:', error);
    }
  }

  /**
   * 获取缓存
   */
  static async get(key) {
    try {
      const value = await redis.get(key);
      if (value) {
        console.log(`缓存命中: ${key}`);
        return JSON.parse(value);
      }
      console.log(`缓存未命中: ${key}`);
      return null;
    } catch (error) {
      console.error('缓存获取失败:', error);
      return null;
    }
  }

  /**
   * 删除缓存
   */
  static async del(key) {
    try {
      await redis.del(key);
      console.log(`缓存删除成功: ${key}`);
    } catch (error) {
      console.error('缓存删除失败:', error);
    }
  }

  /**
   * 批量删除缓存
   */
  static async delPattern(pattern) {
    try {
      const keys = await redis.keys(pattern);
      if (keys.length > 0) {
        await redis.del(...keys);
        console.log(`批量删除缓存成功: ${pattern}, 删除 ${keys.length} 个键`);
      }
    } catch (error) {
      console.error('批量删除缓存失败:', error);
    }
  }

  /**
   * 像素缓存方法
   */
  static async setPixel(gridId, pixelData) {
    const key = `${this.PREFIXES.PIXEL}${gridId}`;
    await this.set(key, pixelData, this.TTL.PIXEL);
  }

  static async getPixel(gridId) {
    const key = `${this.PREFIXES.PIXEL}${gridId}`;
    return await this.get(key);
  }

  /**
   * 用户状态缓存方法
   */
  static async setUserState(userId, state) {
    const key = `${this.PREFIXES.USER_STATE}${userId}`;
    await this.set(key, state, this.TTL.USER_STATE);
  }

  static async getUserState(userId) {
    const key = `${this.PREFIXES.USER_STATE}${userId}`;
    return await this.get(key);
  }

  /**
   * 排行榜缓存方法
   */
  static async setLeaderboard(type, period, data) {
    const key = `${this.PREFIXES.LEADERBOARD}${type}:${period}`;
    await this.set(key, data, this.TTL.LEADERBOARD);
  }

  static async getLeaderboard(type, period) {
    const key = `${this.PREFIXES.LEADERBOARD}${type}:${period}`;
    return await this.get(key);
  }

  /**
   * 聊天消息缓存方法
   */
  static async setChatMessages(channelId, messages) {
    const key = `${this.PREFIXES.CHAT_MESSAGE}${channelId}`;
    await this.set(key, messages, this.TTL.CHAT_MESSAGE);
  }

  static async getChatMessages(channelId) {
    const key = `${this.PREFIXES.CHAT_MESSAGE}${channelId}`;
    return await this.get(key);
  }

  /**
   * 清除缓存方法
   */
  static async clearPixelCache(gridId) {
    await this.del(`${this.PREFIXES.PIXEL}${gridId}`);
    await this.del(`${this.PREFIXES.PIXEL_GRID}${gridId}`);
  }

  static async clearUserCache(userId) {
    await this.del(`${this.PREFIXES.USER_STATE}${userId}`);
    await this.del(`${this.PREFIXES.USER_PROFILE}${userId}`);
  }

  static async clearLeaderboardCache(type) {
    await this.delPattern(`${this.PREFIXES.LEADERBOARD}${type}:*`);
  }
}

module.exports = CacheService;
